import asyncio
import json
import time
from dataclasses import dataclass, field
from enum import Enum
from typing import Any, Callable


# ── Tool safety classification ────────────────────────────────────────────────
class SafetyLevel(Enum):
    READ_ONLY = 'read_only'
    REVERSIBLE = 'reversible'
    IRREVERSIBLE = 'irreversible'
    DANGEROUS = 'dangerous'


# ── Tool definition ───────────────────────────────────────────────────────────
@dataclass
class ToolParam:
    name: str
    type: str  # 'string', 'integer', 'boolean', 'array'
    description: str
    required: bool = True
    enum_values: list[str] | None = None
    example: Any = None


@dataclass
class Tool:
    name: str
    description: str
    parameters: list[ToolParam]
    safety_level: SafetyLevel
    fn: Callable[..., Any]  # actual implementation
    timeout_s: float = 10.0
    max_retries: int = 2

    def schema(self) -> dict:
        """OpenAI function calling schema."""
        props = {}
        required = []
        for p in self.parameters:
            prop: dict = {'type': p.type, 'description': p.description}
            if p.enum_values:
                prop['enum'] = p.enum_values
            if p.example is not None:
                prop['examples'] = [p.example]
            props[p.name] = prop
            if p.required:
                required.append(p.name)
        return {
            'type': 'function',
            'function': {
                'name': self.name,
                'description': self.description,
                'parameters': {
                    'type': 'object',
                    'properties': props,
                    'required': required,
                },
            },
        }


# ── Tool execution result ─────────────────────────────────────────────────────
@dataclass
class ToolResult:
    tool_name: str
    success: bool
    result: Any
    error: str = ''
    duration_ms: float = 0.0
    retries: int = 0

    def to_message(self) -> dict:
        if self.success:
            return {'role': 'tool', 'name': self.tool_name,
                    'content': json.dumps(self.result)}
        return {'role': 'tool', 'name': self.tool_name,
                'content': json.dumps({'error': self.error, 'retries': self.retries})}


# ── Tool registry ─────────────────────────────────────────────────────────────
class ToolRegistry:
    def __init__(self):
        self._tools: dict[str, Tool] = {}

    def register(self, tool: Tool) -> None:
        self._tools[tool.name] = tool

    def get(self, name: str) -> Tool:
        if name not in self._tools:
            raise KeyError(f'Unknown tool: {name}')
        return self._tools[name]

    def schemas(self) -> list[dict]:
        return [t.schema() for t in self._tools.values()]

    def filter_by_safety(self, max_level: SafetyLevel) -> list[dict]:
        order = [SafetyLevel.READ_ONLY, SafetyLevel.REVERSIBLE,
                 SafetyLevel.IRREVERSIBLE, SafetyLevel.DANGEROUS]
        allowed_levels = order[:order.index(max_level) + 1]
        return [t.schema() for t in self._tools.values()
                if t.safety_level in allowed_levels]


# ── Async tool executor with retry ────────────────────────────────────────────
class AsyncToolExecutor:
    def __init__(self, registry: ToolRegistry,
                 confirm_fn: Callable[[str, dict], bool] | None = None):
        self._registry = registry
        self._confirm = confirm_fn  # fn(tool_name, args) -> bool
        self._execution_log: list[ToolResult] = []

    async def execute_one(self, tool_name: str, arguments: dict) -> ToolResult:
        tool = self._registry.get(tool_name)
        t0 = time.perf_counter()

        # Validate arguments
        for param in tool.parameters:
            if param.required and param.name not in arguments:
                return ToolResult(
                    tool_name=tool_name, success=False,
                    result=None, error=f'Missing required parameter: {param.name}',
                )
            if param.enum_values and arguments.get(param.name) not in param.enum_values:
                return ToolResult(
                    tool_name=tool_name, success=False,
                    result=None, error=f'Invalid value for {param.name}: must be one of {param.enum_values}',
                )

        # Confirmation gate for irreversible/dangerous actions
        if tool.safety_level in (SafetyLevel.IRREVERSIBLE, SafetyLevel.DANGEROUS):
            if self._confirm and not self._confirm(tool_name, arguments):
                return ToolResult(
                    tool_name=tool_name, success=False,
                    result=None, error='User declined to confirm action',
                )

        # Execute with retry
        retries = 0
        last_error = ''
        while retries <= tool.max_retries:
            try:
                result = await asyncio.wait_for(
                    asyncio.get_event_loop().run_in_executor(None, lambda: tool.fn(**arguments)),
                    timeout=tool.timeout_s,
                )
                duration = (time.perf_counter() - t0) * 1000
                tr = ToolResult(tool_name=tool_name, success=True,
                                result=result, duration_ms=duration, retries=retries)
                self._execution_log.append(tr)
                return tr
            except asyncio.TimeoutError:
                last_error = f'Tool timed out after {tool.timeout_s}s'
                retries += 1
                if retries <= tool.max_retries:
                    await asyncio.sleep(2 ** retries)
            except Exception as e:
                last_error = str(e)
                retries += 1
                if retries <= tool.max_retries:
                    await asyncio.sleep(2 ** retries)

        duration = (time.perf_counter() - t0) * 1000
        tr = ToolResult(tool_name=tool_name, success=False,
                        result=None, error=last_error,
                        duration_ms=duration, retries=retries - 1)
        self._execution_log.append(tr)
        return tr

    async def execute_parallel(self, tool_calls: list[dict]) -> list[ToolResult]:
        """Execute multiple tool calls concurrently."""
        tasks = [
            self.execute_one(call['name'], call.get('arguments', {}))
            for call in tool_calls
        ]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        # Convert exceptions to ToolResult failures
        final = []
        for i, res in enumerate(results):
            if isinstance(res, Exception):
                final.append(ToolResult(
                    tool_name=tool_calls[i]['name'], success=False,
                    result=None, error=str(res),
                ))
            else:
                final.append(res)
        return final

    def execution_summary(self) -> dict:
        total = len(self._execution_log)
        if not total:
            return {'total': 0}
        success = sum(1 for r in self._execution_log if r.success)
        mean_duration = sum(r.duration_ms for r in self._execution_log) / total
        return {
            'total_calls': total,
            'success_rate': round(success / total, 3),
            'mean_duration_ms': round(mean_duration, 1),
            'total_retries': sum(r.retries for r in self._execution_log),
        }


# ── Demo: agent with parallel tool execution ──────────────────────────────────
if __name__ == '__main__':
    import random

    # Define tools
    def search_web(query: str, max_results: int = 5) -> list[dict]:
        time.sleep(0.05)  # simulate latency
        return [{'title': f'Result {i} for {query}', 'url': f'https://example.com/{i}'}
                for i in range(max_results)]

    def read_file(path: str) -> str:
        if 'missing' in path:
            raise FileNotFoundError(f'File not found: {path}')
        return f'Content of {path}'

    def send_email(to: str, subject: str, body: str) -> dict:
        return {'sent': True, 'message_id': f'msg_{random.randint(1000, 9999)}'}

    registry = ToolRegistry()
    registry.register(Tool(
        name='search_web', description='Search the web for information.',
        parameters=[
            ToolParam('query', 'string', 'Search query', required=True, example='Python LoRA'),
            ToolParam('max_results', 'integer', 'Number of results (1-10)', required=False),
        ],
        safety_level=SafetyLevel.READ_ONLY, fn=search_web,
    ))
    registry.register(Tool(
        name='read_file', description='Read contents of a local file.',
        parameters=[ToolParam('path', 'string', 'Absolute file path', required=True)],
        safety_level=SafetyLevel.READ_ONLY, fn=read_file,
    ))
    registry.register(Tool(
        name='send_email', description='Send an email.',
        parameters=[
            ToolParam('to', 'string', 'Recipient email address', required=True),
            ToolParam('subject', 'string', 'Email subject', required=True),
            ToolParam('body', 'string', 'Email body text', required=True),
        ],
        safety_level=SafetyLevel.IRREVERSIBLE, fn=send_email,
    ))

    # Confirm function (always approves for demo)
    def confirm(tool_name: str, args: dict) -> bool:
        print(f'  [CONFIRM] Action: {tool_name}({args}) — approved')
        return True

    executor = AsyncToolExecutor(registry, confirm_fn=confirm)

    async def demo():
        print('=== Parallel Tool Execution ===')
        tool_calls = [
            {'name': 'search_web', 'arguments': {'query': 'LLM fine-tuning'}},
            {'name': 'read_file', 'arguments': {'path': '/docs/readme.txt'}},
            {'name': 'read_file', 'arguments': {'path': '/docs/missing.txt'}},  # will fail
        ]
        t0 = time.perf_counter()
        results = await executor.execute_parallel(tool_calls)
        elapsed = (time.perf_counter() - t0) * 1000
        print(f'All 3 tools completed in {elapsed:.0f}ms (parallel)')
        for r in results:
            status = 'OK' if r.success else 'FAIL'
            print(f'  [{status}] {r.tool_name}: {str(r.result)[:60] if r.success else r.error}')

        print('\n=== Irreversible Action with Confirmation ===')
        result = await executor.execute_one('send_email', {
            'to': 'user@example.com',
            'subject': 'Report ready',
            'body': 'Your monthly report is attached.',
        })
        print(f'  Result: {result.result}')

        print('\n=== Execution Summary ===')
        print(executor.execution_summary())

    asyncio.run(demo())
